syntax:
while condition:
    # work
    if stop_condition:
        break

SELECT column_list
FROM table_name
WHERE condition;

SELECT column_list
FROM table_name
ORDER BY sort_expression DESC;

SELECT column_list
FROM table_name
LIMIT n OFFSET m;

SELECT column_list
FROM table_name
WHERE text_column LIKE 'pattern%';

SELECT column_list
FROM table_name
WHERE value IN (a, b, c) OR metric BETWEEN low AND high;

SELECT dimension, SUM(metric)
FROM table_name
GROUP BY dimension;

SELECT a.*, b.*
FROM table_a a
INNER JOIN table_b b ON a.key = b.key;

SELECT a.*, b.*
FROM table_a a
LEFT JOIN table_b b ON a.key = b.key;

SELECT a.key, b.key
FROM table_a a
FULL OUTER JOIN table_b b ON a.key = b.key;

SELECT column_list FROM table_a
UNION ALL
SELECT column_list FROM table_b;

SELECT *
FROM table_name
WHERE metric > (SELECT AVG(metric) FROM table_name);

SELECT DATE_TRUNC('week', timestamp_col) AS week_start, COUNT(*)
FROM table_name
GROUP BY 1;
